 * OR TO MANUFACTURE, USE, OR SELL ANYTHING THAT IT  MAY DESCRIBE, IN WHOLE OR IN PART.
 */
var STATES = { LOADING: 'loading', ERROR: 'error', NO_STREAM: 'nostream', PLAYING: 'playing' };
var MAX_RETRIES = 3;
var LOADING_TIMEOUT_MS = 10000;

var hls = null;
var videoEl = null;
var retryCount = 0;
var retryTimer = null;
var loadingTimer = null;
var isNativeHls = false;
var visibilityHandler = null;
var isLive = false;

self.typeParameters = function() {
    return {
        maxDatasources: 1,
        maxDataKeys: 1,
        singleEntity: true,
        previewWidth: '320px',
        previewHeight: '180px'
    };
};

self.onInit = function() {
    var container = self.ctx.$container[0];
    videoEl = container.querySelector('.hls-video');

    // If a previous widget instance parked a <video> in PiP (e.g., the user
    // switched the state entity in the same dashboard, which destroys+recreates
    // the widget), exit that PiP so the old stream doesn't keep playing
    // alongside this new instance. The parked element's `leavepictureinpicture`
    // listener handles the hls destroy and DOM removal.
    var strandedPip = document.pictureInPictureElement;
    if (strandedPip && strandedPip !== videoEl
            && strandedPip.classList && strandedPip.classList.contains('hls-video')) {
        document.exitPictureInPicture().catch(function() {});
    }

    videoEl.addEventListener('seeking', function() {
        if (!isLive) return;
        if (videoEl.buffered.length === 0) return;
        var bufferStart = videoEl.buffered.start(0);
        if (videoEl.currentTime < bufferStart - 0.1) {
            videoEl.currentTime = bufferStart;
        }
    });

    visibilityHandler = function() {
        if (!isLive) return;
        // Don't stop loading while the video is in Picture-in-Picture — PiP needs fresh segments.
        var inPip = typeof document !== 'undefined'
            && document.pictureInPictureElement === videoEl;
        if (document.hidden && !inPip) {
            if (hls) {
                hls.stopLoad();
            }
        } else if (!document.hidden) {
            if (hls) {
                hls.startLoad(-1); // -1 = resume from latest playlist segment (live edge)
            } else if (isNativeHls && videoEl.buffered.length > 0) {
                // Safari native HLS path — jump to the end of the buffered range.
                videoEl.currentTime = videoEl.buffered.end(videoEl.buffered.length - 1);
            }
        }
    };
    document.addEventListener('visibilitychange', visibilityHandler);

    var settings = self.ctx.settings || {};
    videoEl.controls = settings.showControls !== false;
    videoEl.muted = settings.muted !== false;
    videoEl.autoplay = settings.autoplay !== false;

    var retryBtn = container.querySelector('.hls-retry-btn');
    retryBtn.addEventListener('click', function() {
        retryCount = 0;
        if (self.currentUrl) {
            initPlayer(self.currentUrl);
        }
    });

    self.currentUrl = null;
    showState(STATES.NO_STREAM);
};

self.onDataUpdated = function() {
    var url = null;
    var settings = self.ctx.settings || {};

    // Extract URL from subscription data
    if (self.ctx.data && self.ctx.data.length > 0) {
        var cellData = self.ctx.data[0];
        if (cellData.data && cellData.data.length > 0) {
            var latestValue = cellData.data[cellData.data.length - 1][1];
            if (latestValue && typeof latestValue === 'string' && latestValue.trim().length > 0) {
                url = latestValue.trim();
            }
        }
    }

    // Fall back to default URL from settings
    if (!url && settings.defaultStreamUrl) {
        url = settings.defaultStreamUrl.trim();
    }

    // No URL available
    if (!url) {
        if (self.currentUrl) {
            destroyPlayer();
            self.currentUrl = null;
        }
        showState(STATES.NO_STREAM);
        return;
    }

    // URL unchanged — do nothing
    if (url === self.currentUrl) {
        return;
    }

    // New or changed URL
    self.currentUrl = url;
    retryCount = 0;
    initPlayer(url);
};

self.onResize = function() {
    // CSS handles responsive layout — no action needed
};

self.onDestroy = function() {
    // If the widget's <video> is currently in PiP, hand it off so the
    // browser's PiP window keeps receiving media after Angular unmounts
    // this widget. Real cleanup happens when the user closes PiP.
    if (videoEl && typeof document !== 'undefined'
            && document.pictureInPictureElement === videoEl) {

        // Capture current refs in a closure so the deferred cleanup has them
        // after module-level state is cleared for the next widget instance.
        var handoffVideo = videoEl;
        var handoffHls = hls;
        var handoffIsNative = isNativeHls;
        var handoffRetryTimer = retryTimer;
        var handoffLoadingTimer = loadingTimer;

        // Park the element off-screen on document.body so Angular's teardown
        // of the widget container doesn't rip it out of the DOM. The browser
        // holds its own reference in the PiP window either way, but keeping
        // it in-document avoids surprises with some browsers' PiP lifecycle.
        handoffVideo.style.position = 'fixed';
        handoffVideo.style.left = '-9999px';
        handoffVideo.style.top = '0';
        handoffVideo.style.width = '1px';
        handoffVideo.style.height = '1px';
        document.body.appendChild(handoffVideo);

        // Deferred cleanup: runs when the user closes the PiP window.
        handoffVideo.addEventListener('leavepictureinpicture', function onLeave() {
            handoffVideo.removeEventListener('leavepictureinpicture', onLeave);
            if (handoffRetryTimer) {
                clearTimeout(handoffRetryTimer);
            }
            if (handoffLoadingTimer) {
                clearTimeout(handoffLoadingTimer);
            }
            if (handoffHls) {
                try {
                    handoffHls.destroy();
                } catch (e) {
                    // no-op: hls instance may already be torn down
                }
            }
            if (handoffIsNative) {
                handoffVideo.removeAttribute('src');
                try {
                    handoffVideo.load();
                } catch (e) {
                    // no-op: element may be detached
                }
            }
            if (handoffVideo.parentNode) {
                handoffVideo.parentNode.removeChild(handoffVideo);
            }
        });

        // Reset module-level state so the next widget instance starts clean.
        hls = null;
        videoEl = null;
        isNativeHls = false;
        retryCount = 0;
        retryTimer = null;
        loadingTimer = null;
        self.currentUrl = null;
        document.removeEventListener('visibilitychange', visibilityHandler);
        visibilityHandler = null;
        return;
    }

    // Not in PiP — behave exactly as before.
    document.removeEventListener('visibilitychange', visibilityHandler);
    visibilityHandler = null;
    destroyPlayer();
    self.currentUrl = null;
};

function initPlayer(url) {
    destroyPlayer();
    showState(STATES.LOADING);
    startLoadingWatchdog();

    if (typeof Hls !== 'undefined' && Hls.isSupported()) {
        var hlsConfig = {
            maxMaxBufferLength: 180
        };
        var settings = self.ctx.settings || {};
        if (typeof settings.backBufferLength === 'number' && settings.backBufferLength >= 0) {
            hlsConfig.backBufferLength = settings.backBufferLength;
        }
        hls = new Hls(hlsConfig);

        hls.on(Hls.Events.LEVEL_LOADED, function(event, data) {
            isLive = !!(data.details && data.details.live);
        });

        hls.on(Hls.Events.MANIFEST_PARSED, function() {
            showState(STATES.PLAYING);
            if (videoEl.autoplay) {
                attemptAutoplay();
            }
        });

        hls.on(Hls.Events.ERROR, function(event, data) {
            if (!data.fatal) {
                return;
            }
            handleFatalError(data);
        });

        hls.loadSource(url);
        hls.attachMedia(videoEl);

    } else if (videoEl.canPlayType('application/vnd.apple.mpegurl')) {
        // Safari native HLS
        isNativeHls = true;
        videoEl.src = url;

        videoEl.addEventListener('loadedmetadata', function onLoaded() {
            videoEl.removeEventListener('loadedmetadata', onLoaded);
            isLive = !isFinite(videoEl.duration);
            showState(STATES.PLAYING);
            if (videoEl.autoplay) {
                attemptAutoplay();
            }
        });

        videoEl.addEventListener('error', function onError() {
            videoEl.removeEventListener('error', onError);
            showError('Stream playback failed');
        });

    } else {
        showError('HLS is not supported in this browser');
    }
}

function handleFatalError(data) {
    if (retryCount < MAX_RETRIES) {
        retryCount++;
        var delay = Math.pow(2, retryCount - 1) * 1000; // 1s, 2s, 4s

        retryTimer = setTimeout(function() {
            if (!hls) return;

            if (data.type === Hls.ErrorTypes.NETWORK_ERROR) {
                hls.startLoad();
            } else if (data.type === Hls.ErrorTypes.MEDIA_ERROR) {
                hls.recoverMediaError();
            } else {
                // Other fatal error — full reinit
                initPlayer(self.currentUrl);
            }
        }, delay);
    } else {
        var msg = 'Stream error';
        if (data.type === Hls.ErrorTypes.NETWORK_ERROR) {
            msg = 'Network error — could not load stream';
        } else if (data.type === Hls.ErrorTypes.MEDIA_ERROR) {
            msg = 'Media error — stream format issue';
        }
        showError(msg);
    }
}

function attemptAutoplay() {
    var playPromise = videoEl.play();
    if (!playPromise || typeof playPromise.catch !== 'function') {
        return;
    }
    playPromise.catch(function() {
        // Browsers block autoplay with sound unless there's user interaction.
        // Fall back to muted autoplay so the stream still starts; users can
        // unmute via the video controls if they want sound.
        if (!videoEl.muted) {
            videoEl.muted = true;
            videoEl.play().catch(function() {});
        }
    });
}

function showError(message) {
    var container = self.ctx.$container[0];
    var errorMsg = container.querySelector('.hls-error-message');
    errorMsg.textContent = message;
    showState(STATES.ERROR);
}

function showState(state) {
    if (state !== STATES.LOADING) {
        clearLoadingWatchdog();
    }
    var container = self.ctx.$container[0];
    container.querySelector('.hls-loading').style.display = state === STATES.LOADING ? 'flex' : 'none';
    container.querySelector('.hls-error').style.display = state === STATES.ERROR ? 'flex' : 'none';
    container.querySelector('.hls-no-stream').style.display = state === STATES.NO_STREAM ? 'flex' : 'none';
}

function startLoadingWatchdog() {
    clearLoadingWatchdog();
    loadingTimer = setTimeout(function() {
        loadingTimer = null;
        destroyPlayer();
        showError("Can't reach the stream. Check the URL and try again.");
    }, LOADING_TIMEOUT_MS);
}

function clearLoadingWatchdog() {
    if (loadingTimer) {
        clearTimeout(loadingTimer);
        loadingTimer = null;
    }
}

function destroyPlayer() {
    clearLoadingWatchdog();
    if (retryTimer) {
        clearTimeout(retryTimer);
        retryTimer = null;
    }
    if (hls) {
        hls.destroy();
        hls = null;
    }
    if (isNativeHls) {
        videoEl.removeAttribute('src');
        videoEl.load();
        isNativeHls = false;
    }
    isLive = false;
    // retryCount is intentionally NOT reset here — callers that represent a
    // genuine fresh start (URL change, manual retry, onDataUpdated) reset it
    // themselves. Resetting here would allow infinite retries for fatal errors
    // that trigger a full reinit via initPlayer().
}

