self.onDestroy = function() {
    // If the widget's <video> is currently in PiP, hand it off so the
    // browser's PiP window keeps receiving media after Angular unmounts
    // this widget. Real cleanup happens when the user closes PiP.
    if (videoEl && typeof document !== 'undefined'
            && document.pictureInPictureElement === videoEl) {

        // Capture current refs in a closure so the deferred cleanup has them
        // after module-level state is cleared for the next widget instance.
        var handoffVideo = videoEl;
        var handoffPc = pc;
        var handoffSessionUrl = sessionUrl;
        var handoffRetryTimer = retryTimer;
        var handoffLoadingTimer = loadingTimer;

        // Park the element off-screen on document.body so Angular's teardown
        // of the widget container doesn't rip it out of the DOM. The browser
        // holds its own reference in the PiP window either way, but keeping
        // it in-document avoids surprises with some browsers' PiP lifecycle.
        handoffVideo.style.position = 'fixed';
        handoffVideo.style.left = '-9999px';
        handoffVideo.style.top = '0';
        handoffVideo.style.width = '1px';
        handoffVideo.style.height = '1px';
        document.body.appendChild(handoffVideo);

        // Deferred cleanup: runs when the user closes the PiP window.
        handoffVideo.addEventListener('leavepictureinpicture', function onLeave() {
            handoffVideo.removeEventListener('leavepictureinpicture', onLeave);
            if (handoffRetryTimer) {
                clearTimeout(handoffRetryTimer);
            }
            if (handoffLoadingTimer) {
                clearTimeout(handoffLoadingTimer);
            }
            if (handoffSessionUrl) {
                // Best-effort WHEP DELETE to release the server-side session.
                try {
                    fetch(handoffSessionUrl, { method: 'DELETE' }).catch(function() {});
                } catch (e) {
                    // no-op: fetch may throw synchronously in pathological cases
                }
            }
            if (handoffPc) {
                try {
                    handoffPc.close();
                } catch (e) {
                    // no-op: peer connection may already be closed
                }
            }
            try {
                handoffVideo.srcObject = null;
            } catch (e) {
                // no-op: element may be detached
            }
            if (handoffVideo.parentNode) {
                handoffVideo.parentNode.removeChild(handoffVideo);
            }
        });

        // Reset module-level state so the next widget instance starts clean.
        pc = null;
        sessionUrl = null;
        videoEl = null;
        liveBadge = null;
        retryCount = 0;
        retryTimer = null;
        loadingTimer = null;
        self.currentUrl = null;
        return;
    }

    // Not in PiP — tear down immediately.
    destroyPlayer();
    self.currentUrl = null;
};

function initPlayer(url) {
    destroyPlayer();
    showState(STATES.LOADING);
    startLoadingWatchdog();

    if (typeof RTCPeerConnection === 'undefined') {
        showError('WebRTC is not supported in this browser');
        return;
    }

    var settings = self.ctx.settings || {};
    var rtcConfig = {};
    if (settings.stunServer && typeof settings.stunServer === 'string' && settings.stunServer.trim().length > 0) {
        rtcConfig.iceServers = [{ urls: settings.stunServer.trim() }];
    }

    var localPc = new RTCPeerConnection(rtcConfig);
    pc = localPc;

    localPc.addTransceiver('video', { direction: 'recvonly' });
    localPc.addTransceiver('audio', { direction: 'recvonly' });

    localPc.ontrack = function(ev) {
        if (!videoEl) return;
        if (ev.streams && ev.streams[0] && videoEl.srcObject !== ev.streams[0]) {
            videoEl.srcObject = ev.streams[0];
        }
    };

    localPc.onconnectionstatechange = function() {
        // Ignore state changes for a peer connection that has been replaced or torn down.
        if (localPc !== pc) return;
        var state = localPc.connectionState;
        if (state === 'connected') {
            showState(STATES.PLAYING);
            if (videoEl && videoEl.autoplay) {
                attemptAutoplay();
            }
        } else if (state === 'failed' || state === 'disconnected' || state === 'closed') {
            handleFatalError(new Error('WebRTC ' + state));
        }
    };

    localPc.createOffer()
        .then(function(offer) {
            return localPc.setLocalDescription(offer).then(function() { return offer; });
        })
        .then(function(offer) {
            return fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/sdp',
                    'Accept': 'application/sdp'
                },
                body: offer.sdp
            });
        })
        .then(function(resp) {
            if (!resp.ok) {
                throw new Error('WHEP HTTP ' + resp.status);
            }
            var loc = resp.headers.get('Location');
            if (loc) {
                try {
                    sessionUrl = new URL(loc, url).toString();
                } catch (e) {
                    sessionUrl = loc;
                }
            }
            return resp.text();
        })
        .then(function(answerSdp) {
            // If the widget was torn down mid-flight, `pc` will have been cleared.
            if (localPc !== pc) return;
            return localPc.setRemoteDescription({ type: 'answer', sdp: answerSdp });
        })
        .catch(function(err) {
            // Swallow errors from superseded peer connections.
            if (localPc !== pc) return;
            handleFatalError(err);
        });
}

function handleFatalError(err) {
    if (retryCount < MAX_RETRIES) {
        retryCount++;
        var delay = Math.pow(2, retryCount - 1) * 1000; // 1s, 2s, 4s

        retryTimer = setTimeout(function() {
            retryTimer = null;
            if (self.currentUrl) {
                initPlayer(self.currentUrl);
            }
        }, delay);
    } else {
        if (err && err.message) {
            console.warn('[WebRTC widget] giving up after ' + MAX_RETRIES + ' retries:', err.message);
        }
        showError("Can't reach the stream. Check the URL and try again.");
    }
}

function attemptAutoplay() {
    if (!videoEl) return;
    var playPromise = videoEl.play();
    if (!playPromise || typeof playPromise.catch !== 'function') {
        return;
    }
    playPromise.catch(function() {
        // Browsers block autoplay with sound unless there's user interaction.
        // Fall back to muted autoplay so the stream still starts; users can
        // unmute via the video controls if they want sound.
        if (videoEl && !videoEl.muted) {
            videoEl.muted = true;
            videoEl.play().catch(function() {});
        }
    });
}

function showError(message) {
    var container = self.ctx.$container[0];
    var errorMsg = container.querySelector('.webrtc-error-message');
    errorMsg.textContent = message;
    showState(STATES.ERROR);
}

function showState(state) {
    if (state !== STATES.LOADING) {
        clearLoadingWatchdog();
    }
    var container = self.ctx.$container[0];
    container.querySelector('.webrtc-loading').style.display = state === STATES.LOADING ? 'flex' : 'none';
    container.querySelector('.webrtc-error').style.display = state === STATES.ERROR ? 'flex' : 'none';
    container.querySelector('.webrtc-no-stream').style.display = state === STATES.NO_STREAM ? 'flex' : 'none';

    // LIVE badge shows only while playing and only when the setting allows it.
    if (liveBadge) {
        var settings = self.ctx.settings || {};
        var showBadge = state === STATES.PLAYING && settings.showLiveIndicator !== false;
        liveBadge.style.display = showBadge ? 'flex' : 'none';
    }
}

function startLoadingWatchdog() {
    clearLoadingWatchdog();
    loadingTimer = setTimeout(function() {
        loadingTimer = null;
        destroyPlayer();
        showError("Can't reach the stream. Check the URL and try again.");
    }, LOADING_TIMEOUT_MS);
}

function clearLoadingWatchdog() {
    if (loadingTimer) {
        clearTimeout(loadingTimer);
        loadingTimer = null;
    }
}

function destroyPlayer() {
    clearLoadingWatchdog();
    if (retryTimer) {
        clearTimeout(retryTimer);
        retryTimer = null;
    }
    // Best-effort WHEP DELETE to release the server-side session.
    if (sessionUrl) {
        try {
            fetch(sessionUrl, { method: 'DELETE' }).catch(function() {});
        } catch (e) {
            // no-op: fetch may throw synchronously in pathological cases
        }
        sessionUrl = null;
    }
    if (pc) {
        try {
            pc.close();
        } catch (e) {
            // no-op: peer connection may already be closed
        }
        pc = null;
    }
    if (videoEl) {
        try {
            videoEl.srcObject = null;
        } catch (e) {
            // no-op
        }
    }
    // retryCount is intentionally NOT reset here — callers that represent a
    // genuine fresh start (URL change, manual retry, onDataUpdated) reset it
    // themselves. Resetting here would allow infinite retries for fatal errors
    // that trigger a full reinit via initPlayer().
}
